+/**
+ * Validate that a sync URL is safe to use.
+ * Only allow same-origin URLs or explicitly trusted domains.
+ */
+export function isValidSyncURL(urlString: string): boolean {
+  try {
+    const url = new URL(urlString);
+    
+    // Disallow non-HTTPS URLs in production
+    if (process.env.NODE_ENV === 'production' && url.protocol !== 'https:') {
+      return false;
+    }
+    
+    // Check if same-origin
+    if (typeof window !== 'undefined' && window.location) {
+      if (url.origin === window.location.origin) {
+        return true;
+      }
+    }
+    
+    // Add additional validation for trusted domains if needed
+    // For now, only same-origin URLs are allowed
+    return false;
+    
+  } catch (e) {
+    // Invalid URL format
+    return false;
+  }
+}

