+package org.apache.streampipes.extensions.management.util;
+
+import java.net.URL;
+import java.util.Arrays;
+import java.util.List;
+
+public class SsrfUrlValidator {
+  
+  private static final List<String> ALLOWED_PROTOCOLS = Arrays.asList("http", "https");
+  private static final List<String> DISALLOWED_HOSTS = Arrays.asList(
+      "localhost",
+      "127.0.0.1",
+      "::1",
+      "0.0.0.0"
+  );
+  
+  /**
+   * Validates if a URL is allowed to prevent SSRF attacks.
+   * @param url The URL to validate
+   * @return true if the URL is allowed, false otherwise
+   */
+  public static boolean isAllowed(URL url) {
+    // Validate protocol
+    if (!ALLOWED_PROTOCOLS.contains(url.getProtocol().toLowerCase())) {
+      return false;
+    }
+    
+    // Validate host - disallow internal/loopback addresses
+    String host = url.getHost().toLowerCase();
+    return !DISALLOWED_HOSTS.contains(host) 
+        && !host.endsWith(".internal")
+        && !host.equals("[::1]");
+  }
+}

